@namespace sv_a17abfe191964c52a9e6e073129e592c.Components.Pages.Apply

<nav aria-label="Application progress" class="step-indicator mb-4">
    <ol class="list-unstyled d-flex justify-content-between align-items-center mb-0">
        @for (var i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isFuture = !isCurrent && !isCompleted;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")">
                @if (isCompleted)
                {
                    <button class="btn btn-link step-btn p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-circle bg-success text-white">✓</span>
                        <span class="step-label d-block mt-1 text-success fw-semibold">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <div class="step-content">
                        <span class="step-circle @(isCurrent ? "bg-primary text-white" : "bg-secondary text-white")">@(stepIndex + 1)</span>
                        <span class="step-label d-block mt-1 @(isCurrent ? "text-primary fw-semibold" : "text-muted")">@StepNames[stepIndex]</span>
                    </div>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlyList<string> StepNames { get; set; } = [];
    [Parameter, EditorRequired] public IReadOnlySet<int> CompletedSteps { get; set; } = new HashSet<int>();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

