toolArgs.file_text:
.step-indicator ol {
    counter-reset: step;
    position: relative;
}

.step-item {
    position: relative;
}

.step-item + .step-item::before {
    content: "";
    position: absolute;
    top: 16px;
    left: -50%;
    width: 100%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed + .step-item::before {
    background-color: #198754;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 32px;
    height: 32px;
    border-radius: 50%;
    font-size: 0.85rem;
    font-weight: 600;
    position: relative;
    z-index: 1;
}

.step-label {
    font-size: 0.8rem;
}

.step-btn {
    border: none;
    background: none;
    cursor: pointer;
}

.step-btn:hover .step-label {
    text-decoration: underline;
}

.future {
    opacity: 0.5;
}

