@namespace sv_a17abfe191964c52a9e6e073129e592c.Components.Pages.Apply

<h4 class="mb-4">Cover Letter</h4>

<div class="mb-3">
    <label class="form-label">Write your cover letter</label>
    <textarea class="form-control" rows="12" maxlength="@MaxLength"
              @bind="CoverLetter" @bind:event="oninput"
              @bind:after="NotifyChanged"></textarea>
    <div class="form-text text-end">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="OnNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private async Task NotifyChanged()
    {
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }
}

@namespace sv_a17abfe191964c52a9e6e073129e592c.Components.Pages.Apply
@using sv_a17abfe191964c52a9e6e073129e592c.Models

<h4 class="mb-4">Review & Submit</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-2">🎉 Application Submitted!</h5>
        <p class="mb-0">Your application has been received. Your application ID is <strong>#@ApplicationId</strong>.</p>
    </div>
}
else
{
    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate?.ToString("MMM yyyy") – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy"))
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) — @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between mt-4">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private bool IsSubmitting;
    private bool IsSubmitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        ErrorMessage = null;

        try
        {
            var application = new JobApplication(
                Personal.ToRecord(),
                new WorkHistory(WorkEntries.Select(e => e.ToRecord()).ToList()),
                References.Select(r => r.ToRecord()).ToList(),
                CoverLetter
            );

            ApplicationId = await ApplicationService.SubmitApplicationAsync(application);
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

@page "/apply"
@namespace sv_a17abfe191964c52a9e6e073129e592c.Components.Pages.Apply
@using sv_a17abfe191964c52a9e6e073129e592c.Models
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep"
                   StepNames="_stepNames"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep Model="_personalInfo"
                              ApplicationService="ApplicationService"
                              OnNext="() => CompleteAndAdvance(0)" />
            break;
        case 1:
            <WorkHistoryStep Entries="_workEntries"
                             OnNext="() => CompleteAndAdvance(1)"
                             OnBack="() => GoToStep(_currentStep - 1)" />
            break;
        case 2:
            <ReferencesStep References="_references"
                            OnNext="() => CompleteAndAdvance(2)"
                            OnBack="() => GoToStep(_currentStep - 1)" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="_coverLetter"
                             CoverLetterChanged="v => _coverLetter = v"
                             OnNext="() => CompleteAndAdvance(3)"
                             OnBack="() => GoToStep(_currentStep - 1)" />
            break;
        case 4:
            <ReviewStep Personal="_personalInfo"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="_coverLetter"
                        ApplicationService="ApplicationService"
                        OnEditStep="GoToStep"
                        OnBack="() => GoToStep(_currentStep - 1)" />
            break;
    }
</div>

@code {
    private static readonly IReadOnlyList<string> _stepNames = new[]
    {
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    };

    private int _currentStep;
    private readonly HashSet<int> _completedSteps = new();

    private readonly PersonalInfoModel _personalInfo = new();
    private readonly List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
    private readonly List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };
    private string _coverLetter = "";

    private void CompleteAndAdvance(int step)
    {
        _completedSteps.Add(step);
        _currentStep = step + 1;
    }

    private void GoToStep(int step)
    {
        if (step >= 0 && step < _stepNames.Count)
        {
            _currentStep = step;
        }
    }
}

